#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv2d_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    auto N = x.size(0);
    auto C = x.size(1);
    auto H = x.size(2);
    auto W = x.size(3);
    auto OC = weight.size(0);
    auto KH = weight.size(2);
    auto KW = weight.size(3);

    TORCH_CHECK(C == weight.size(1), "Input C must match weight C");
    TORCH_CHECK(KH == 3 && KW == 3, "Kernel must be 3x3");
    TORCH_CHECK(x.scalar_type() == at::kFloat, "Only float32 supported");
    TORCH_CHECK(weight.scalar_type() == at::kFloat, "Only float32 supported");

    auto HOut = H - KH + 1;
    auto WOut = W - KW + 1;
    at::Tensor y = at::empty({N, OC, HOut, WOut}, x.options());

    EXEC_NPU_CMD(aclnnConvStandard2dAsymmetricInputSquareKernelCustom, x, weight, y);
    return y;
